"use strict";(globalThis.webpackChunk_servicenow_sdk_docs=globalThis.webpackChunk_servicenow_sdk_docs||[]).push([[39847],{67827(o){o.exports=JSON.parse('{"tag":{"label":"Flow","permalink":"/sdk/tags/flow","allTagsPath":"/sdk/tags","count":4,"items":[{"id":"api/flow/flow-api","title":"Function: Flow(config, triggerInstance, body)","description":"Creates a Flow record (syshubflow) that defines a series of actions to execute when triggered.","permalink":"/sdk/api/flow/flow-api"},{"id":"api/flow/subflow-api","title":"Function: Subflow(config, body)","description":"Creates a reusable Subflow with typed inputs, outputs, and an optional body. Subflows are invoked from inside a Flow or another Subflow via wfa.subflow().","permalink":"/sdk/api/flow/subflow-api"},{"id":"api/flow/wfa-api","title":"wfa","description":"The wfa (Workflow Activity) namespace provides the core building blocks for defining Flows and Subflows. Use wfa.trigger() to start a flow, wfa.action() to execute built-in actions, and wfa.flowLogic for control flow (If/Else, ForEach, GoBackTo).","permalink":"/sdk/api/flow/wfa-api"},{"id":"guides/wfa-flow-guide","title":"Workflow Automation Flow Guide","description":"Comprehensive guide for creating and editing ServiceNow Workflow Automation (WFA) flows using the Fluent SDK. Covers Flow Designer flows including triggers, actions, flow logic, data pills, approvals, and service catalog integration. Use this when implementing event-driven automation, scheduled tasks, approval workflows, or any WFA component.","permalink":"/sdk/guides/wfa-flow-guide"}],"unlisted":false}}')}}]);